/**
 * Bundle pea_master.json into a TypeScript module for Cloudflare Pages Functions.
 * 
 * Writes to functions/_shared/pea_master_bundle.ts — the actual location
 * consumed by the data-loader at build time.
 *
 * Usage: node scripts/bundle_data.js
 */
const fs = require('fs');
const path = require('path');

const inputPath = path.resolve(__dirname, '..', 'data', 'pea_master.json');
const outputDir = path.resolve(__dirname, '..', 'functions', '_shared');
const outputPath = path.join(outputDir, 'pea_master_bundle.ts');

if (!fs.existsSync(inputPath)) {
  console.error(`ERROR: ${inputPath} not found. Run 'npm run data:extract' first.`);
  process.exit(1);
}

const jsonData = fs.readFileSync(inputPath, 'utf-8');

try {
  JSON.parse(jsonData);
} catch (e) {
  console.error('ERROR: Invalid JSON in pea_master.json');
  process.exit(1);
}

// Ensure output directory exists
if (!fs.existsSync(outputDir)) {
  fs.mkdirSync(outputDir, { recursive: true });
}

const tsContent = `// AUTO-GENERATED — do not edit manually
// Generated by: node scripts/bundle_data.js
// Source: data/pea_master.json

const data = ${jsonData} as const;
export default data;
`;

fs.writeFileSync(outputPath, tsContent, 'utf-8');
const sizeKB = (Buffer.byteLength(tsContent, 'utf-8') / 1024).toFixed(1);
console.log(`[OK] Bundled data: ${outputPath} (${sizeKB} KB)`);
